// ========== PHASE 1: GET & PARSE TASK ==========
// Merged from: Filter A Task + JSON Parse

const tasks = $input.all().map(item => item.json);
if (tasks.length === 0) return [];

// Sort by priority: test_mode > batch_priority > sequence > created_at
const sortedTasks = tasks.sort((a, b) => {
  const testModeA = a.test_mode === true || a.test_mode === 'true';
  const testModeB = b.test_mode === true || b.test_mode === 'true';
  if (testModeA && !testModeB) return -1;
  if (!testModeA && testModeB) return 1;

  if (a.batch_priority && b.batch_priority) {
    const priorityA = new Date(a.batch_priority).getTime();
    const priorityB = new Date(b.batch_priority).getTime();
    if (priorityA !== priorityB) return priorityA - priorityB;
  } else if (a.batch_priority) return -1;
  else if (b.batch_priority) return 1;

  const seqA = parseInt(a.sequence) || 1;
  const seqB = parseInt(b.sequence) || 1;
  if (seqA !== seqB) return seqA - seqB;

  if (a.created_at && b.created_at) {
    return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
  }
  return 0;
});

const t = sortedTasks[0];

// Parse JSON string fields safely
const safeParse = (val, fallback) => {
  if (!val) return fallback;
  if (typeof val === 'object' && val !== null) return val;
  try { return JSON.parse(val); } catch { return fallback; }
};

return {
  ...t,
  task_id: t.task_id || '',
  supabase_task_id: t.supabase_task_id || t.id,
  launch_id: t.launch_id || null,
  user_id: t.user_id || null,
  batch_id: t.batch_id || '',
  extra: safeParse(t.extra, {}),
  data: safeParse(t.data, {}),
  ai_settings: safeParse(t.ai_settings, {}),
  hierarchy_path: safeParse(t.hierarchy_path, []),
  step_number: parseInt(t.step_number) || 1,
  stage_key: t.stage_key || '',
  parent_task_id: t.parent_task_id || null,
  split_group_id: t.split_group_id || null,
  test_mode: t.test_mode === true || t.test_mode === 'true',
  requires_approval: t.requires_approval === true || t.requires_approval === 'true',
  _retry_count: 0
};

// ========== PHASE 2: PRE-PROCESS ==========
// Merged from: Check Pre-Process + Execute Pre-Process Webhook
//              + Merge Pre-Process Output + Handle Pre-Process Failure

const task = $json;
const cfg = task.extra?.pre_process;

// Skip if pre-process not enabled or no URL
if (!cfg?.enabled || !cfg?.webhook_url) {
  return { ...task, _pre_process_skipped: true };
}

try {
  const method = cfg.webhook_method || 'POST';
  const res = await this.helpers.httpRequest({
    method,
    url: cfg.webhook_url,
    body: task.data,
    json: true,
    timeout: 30000
  });

  // Merge output based on output_handling config
  let mergedData = { ...task.data };
  const outputHandling = cfg.output_handling || 'merge';

  if (outputHandling === 'replace') {
    mergedData = res;
  } else if (outputHandling === 'merge') {
    mergedData = { ...mergedData, ...res };
  } else if (outputHandling === 'nested') {
    const fieldName = cfg.nested_field_name || 'pre_output';
    mergedData[fieldName] = res;
  }

  return { ...task, data: mergedData, _pre_process_executed: true };

} catch (error) {
  const onFailure = cfg.on_failure || 'continue';

  if (onFailure === 'abort') {
    throw new Error('Pre-process webhook failed: ' + error.message);
  }

  // Continue with original data
  return {
    ...task,
    _pre_process_failed: true,
    _pre_process_error: error.message
  };
}

console.log('--- Phase 3: Start Parsing ---');
// ========== PHASE 3: PARSE AI RESULT & REPORT KEY STATUS ==========
// Merged from: Convert MarkdownJSON to JSON + Report Success + Report Failure
//              + Retry Logic + Add AlongWith Attributes

// USE PRE-PROCESS OUTPUT (Phase 2) as source of truth for extra/data/metadata
const taskInfo = $('2. Pre-Process').first().json;
const keyInfo = $('Get Key').first().json;
const apiRes = $json;

// Use static data to persist retry count across Wait node resumes
const staticData = $getWorkflowStaticData('global');
const retryCount = staticData.retryCount || 0;
const maxRetries = 3;

// --- 1. HANDLE API ERROR ---
if (apiRes.error || !apiRes.candidates) {
  // Report failure to key rotation manager
  try {
    const errorStatus = apiRes.error?.status || 'API_ERROR';
    const errorMessage = apiRes.error?.message || '';
    const fullErrorCode = `[${errorStatus}] ${errorMessage}`;

    await this.helpers.httpRequestWithAuthentication.call(this, 'httpBasicAuth', {
      method: 'POST',
      url: 'https://n8n.teky.vn/webhook/set-key-state',
      body: {
        key_id: keyInfo.key_id,
        status: 'fail',
        error_code: fullErrorCode
      },
      json: true
    });
  } catch (e) { /* ignore reporting error */ }

  if (retryCount < maxRetries - 1) {
    staticData.retryCount = retryCount + 1;
    return { _retry: true, _retry_count: retryCount + 1, _err: apiRes.error?.message };
  }

  // Max retries reached — reset counter and throw
  staticData.retryCount = 0;
  throw new Error('Max retries reached. All available keys failed. Last error: ' + (apiRes.error?.message || 'Unknown'));
}

// --- 2. PARSE JSON FROM AI RESPONSE ---
function convertMarkdownJsonToJsObject(partsArray) {
  const fullText = partsArray.map(part => part.text).join('');
  let trimmed = fullText.trim();

  let jsonContent;
  if (trimmed.startsWith('```json')) {
    jsonContent = trimmed.slice(7, trimmed.lastIndexOf('```')).trim();
  } else if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
    jsonContent = trimmed;
  } else {
    throw new Error('Invalid JSON format - response does not start with ```json, { or [');
  }

  // Remove control chars
  jsonContent = jsonContent.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, '');
  return JSON.parse(jsonContent);
}

let result;
try {
  const partsArray = apiRes.candidates[0].content.parts;
  result = convertMarkdownJsonToJsObject(partsArray);
} catch (parseError) {
  if (retryCount < maxRetries - 1) {
    staticData.retryCount = retryCount + 1;
    return { _retry: true, _retry_count: retryCount + 1, _err: 'JSON Parse Fail: ' + parseError.message };
  }
  staticData.retryCount = 0;
  const rawSnippet = apiRes.candidates[0].content.parts.map(p => p.text).join('').substring(0, 200);
  console.error('JSON Parse Failed. Raw Snippet:', rawSnippet);
  throw new Error(`Invalid JSON in AI response: ${parseError.message}. Snippet: ${rawSnippet}`);
}

// --- 3. REPORT SUCCESS ---
try {
  await this.helpers.httpRequestWithAuthentication.call(this, 'httpBasicAuth', {
    method: 'POST',
    url: 'https://n8n.teky.vn/webhook/set-key-state',
    body: { key_id: keyInfo.key_id, status: 'success' },
    json: true
  });
} catch (e) { /* ignore reporting error */ }

// Reset retry counter on success
staticData.retryCount = 0;

// --- 4. ADD RETURN-ALONG-WITH ATTRIBUTES ---
const extra = taskInfo.extra || {};
const data = taskInfo.data || {};
const returnAlongWith = extra['return-along-with'] || [];
if (returnAlongWith.length > 0) {
  for (const key of returnAlongWith) {
    if (data.hasOwnProperty(key)) {
      result[key] = data[key];
    }
  }
}

return {
  ...taskInfo,
  task_id: taskInfo.task_id || '',
  task_type: taskInfo.task_type || '',
  result: result,
  extra: extra,
  data: data,
  supabase_task_id: taskInfo.supabase_task_id || taskInfo.id,
  batch_id: taskInfo.batch_id || '',
  launch_id: taskInfo.launch_id || null,
  user_id: taskInfo.user_id || null,
  test_mode: taskInfo.test_mode === true || taskInfo.test_mode === 'true',
  status: 'generated', // ✅ Mark task as generated for DB update
  root_task_id: taskInfo.root_task_id || null,
  hierarchy_path: taskInfo.hierarchy_path || [],
  step_number: parseInt(taskInfo.step_number) || 1,
  stage_key: taskInfo.stage_key || '',
  parent_task_id: taskInfo.parent_task_id || null,
  split_group_id: taskInfo.split_group_id || null,
  requires_approval: taskInfo.requires_approval === true || taskInfo.requires_approval === 'true',
  sequence: taskInfo.sequence || null
};

// ========== PHASE 4: POST-PROCESS ==========
// Merged from: Check Post-Process + Execute Post-Process Webhook
//              + Handle Post-Process Result

const task = $json;
const extra = task.extra || {};
const cfg = extra.post_process;

// Skip if post-process not enabled
if (!cfg?.enabled || !cfg?.webhook_url) {
  return { ...task, _post_process_skipped: true };
}

let requestBody;
const inputSource = cfg.input_source || 'output_only';

if (inputSource === 'output_only') {
  requestBody = task.result;
} else if (inputSource === 'input_and_output') {
  requestBody = { input: task.data, output: task.result };
} else {
  requestBody = task.result;
}

try {
  const method = cfg.webhook_method || 'POST';
  const res = await this.helpers.httpRequest({
    method,
    url: cfg.webhook_url,
    body: requestBody,
    json: true,
    timeout: 30000
  });

  return {
    ...task,
    _post_process_executed: true,
    _post_process_response: res
  };

} catch (error) {
  const onFailure = cfg.on_failure || 'continue';

  if (onFailure === 'abort') {
    throw new Error('Post-process webhook failed: ' + error.message);
  }

  return {
    ...task,
    _post_process_failed: true,
    _post_process_error: error.message
  };
}

// ========== PHASE 5: DETERMINE & CREATE NEXT STAGE TASKS ==========

const task = $json;
const extra = task.extra || {};
const currentStageConfig = extra.current_stage_config || null;

let nextConfigs = extra.next_stage_configs || extra.next_stage_config || [];
if (!Array.isArray(nextConfigs)) nextConfigs = [nextConfigs];

const grt = extra.grt || {};

if (!currentStageConfig || nextConfigs.length === 0) {
  return {
    action: 'terminate',
    task_id: task.supabase_task_id,
    message: 'No next stage configured - final stage reached'
  };
}

const cardinality = currentStageConfig.cardinality || 'one_to_one';
const result = task.result;
const inputData = task.data || {};

function extractStageKey(templateId) {
  if (!templateId) return 'unknown_stage';
  const parts = templateId.split('_');
  if (parts.length < 2) return templateId;
  return parts.slice(1).join('_');
}

const currentStageKey = task.stage_key || (currentStageConfig.template_id ? extractStageKey(currentStageConfig.template_id) : 'unknown_stage');
const rootId = task.root_task_id || task.supabase_task_id;
const hierarchyPath = [...(task.hierarchy_path || []), task.supabase_task_id];
const currentStepNumber = parseInt(task.step_number) || 1;

function buildTaskMetadata(nextConfig, index, total, dataForTask) {
  const nextTplId = nextConfig.template_id || nextConfig.prompt_id;
  const nextStageKey = extractStageKey(nextTplId);
  const taskTypeMatch = nextTplId.match(/^[0-9a-f-]+_(.+)$/);
  const taskType = taskTypeMatch ? taskTypeMatch[1] : nextStageKey;
  const childRouting = grt[nextTplId] || {};
  const grandChildIds = childRouting.next_ids || [];
  const grandChildConfigs = grandChildIds.map(gcId => {
    const gcInfo = grt[gcId];
    if (!gcInfo) return null;
    return {
      template_id: gcInfo.template_id,
      prompt_id: gcInfo.prompt_id,
      cardinality: gcInfo.cardinality,
      split_mode: gcInfo.split_mode,
      split_path: gcInfo.split_path,
      output_mapping: gcInfo.output_mapping
    };
  }).filter(Boolean);

  return {
    prompt_template_id: childRouting.template_id || nextTplId,
    task_type: taskType,
    input_data: dataForTask,
    parent_task_id: task.supabase_task_id,
    root_task_id: rootId,
    hierarchy_path: hierarchyPath,
    batch_id: task.batch_id || null,
    user_id: task.user_id || null,
    launch_id: task.launch_id || null,
    test_mode: task.test_mode || false,
    sequence: index + 1,
    total_steps: total,
    status: 'plan',
    stage_key: nextStageKey,
    step_number: currentStepNumber + 1,
    split_group_id: task.split_group_id,
    requires_approval: childRouting.requires_approval || task.requires_approval || false,
    extra: {
      current_stage_config: {
        template_id: childRouting.template_id || nextTplId,
        prompt_id: childRouting.prompt_id || null,
        cardinality: childRouting.cardinality || 'one_to_one',
        split_path: childRouting.split_path || null,
        split_mode: childRouting.split_mode || 'per_item',
        output_mapping: childRouting.output_mapping || 'result'
      },
      next_stage_configs: grandChildConfigs,
      grt: grt,
      parent_stage_key: currentStageKey,
      parent_task_id: task.supabase_task_id
    }
  };
}

let finalTasks = [];
if (cardinality === 'one_to_one') {
  finalTasks = nextConfigs.map((cfg, idx) => buildTaskMetadata(cfg, idx, 1, result));
} else if (cardinality === 'one_to_many') {
  const splitPath = currentStageConfig.split_path || 'result';
  const pathParts = splitPath.split('.');
  let arrayToSplit = result;
  for (const part of pathParts) {
    if (part === 'result') continue;
    arrayToSplit = arrayToSplit?.[part];
  }
  if (Array.isArray(arrayToSplit)) {
    const splitMode = currentStageConfig.split_mode || 'per_item';
    for (const nextConfig of nextConfigs) {
      if (splitMode === 'per_item') {
        arrayToSplit.forEach((item, idx) => {
          finalTasks.push(buildTaskMetadata(nextConfig, idx, arrayToSplit.length, {
            ...inputData,
            user_id: task.user_id || null,
            batch_id: task.batch_id || null,
            launch_id: task.launch_id || null,
            item: item,
            _split_index: idx,
            _split_total: arrayToSplit.length
          }));
        });
      } else if (splitMode === 'per_batch') {
        const batchSize = currentStageConfig.batch_size || 10;
        for (let i = 0, bIdx = 0; i < arrayToSplit.length; i += batchSize, bIdx++) {
          const batchItems = arrayToSplit.slice(i, i + batchSize);
          finalTasks.push(buildTaskMetadata(nextConfig, bIdx, Math.ceil(arrayToSplit.length / batchSize), {
            ...inputData,
            user_id: task.user_id || null,
            batch_id: task.batch_id || null,
            launch_id: task.launch_id || null,
            items: batchItems,
            _batch_index: bIdx
          }));
        }
      }
    }
  }
}

return {
  action: finalTasks.length > 0 ? 'create_tasks_for_branches' : 'terminate',
  tasks: finalTasks,
  total_count: finalTasks.length,
  task_id: task.supabase_task_id
};

// ========== PHASE 6: CREATE NEXT STAGE TASKS ==========

const config = $json;

if (config.action === 'terminate') return [];
if (config.action === 'error') throw new Error(config.message);

if (config.action === 'create_tasks_for_branches') {
  return config.tasks.map(task => ({
    prompt_template_id: task.prompt_template_id,
    task_type: task.task_type || '',
    input_data: task.input_data,
    parent_task_id: task.parent_task_id,
    root_task_id: task.root_task_id,
    hierarchy_path: task.hierarchy_path,
    batch_id: task.batch_id || null,
    user_id: task.user_id || null,
    launch_id: task.launch_id || null,
    test_mode: task.test_mode,
    sequence: task.sequence,
    total_steps: task.total_steps,
    status: task.status || 'plan',
    stage_key: task.stage_key,
    step_number: task.step_number,
    split_group_id: task.split_group_id,
    requires_approval: task.requires_approval,
    extra: task.extra
  }));
}

return [];

